    def _run_command(
        self,
        cmd: list,
        check: bool = True,
        capture_output: bool = True,
        env: Optional[dict] = None,
    ) -> subprocess.CompletedProcess:
        """
        Run a subprocess command securely.

        Security considerations:
        - Uses list form (not shell=True) to prevent injection
        - Validates command components
        - Captures and logs output
        """
        # Validate that command components don't contain shell metacharacters
        for arg in cmd:
            if any(c in str(arg) for c in [';', '|', '&', '`', '$', '(', ')']):
                raise ValueError(
                    f"Potentially unsafe character in command argument: {arg}"
                )

        merged_env = os.environ.copy()
        if env:
            merged_env.update(env)

        # Security: Don't pass through potentially dangerous env vars
        for dangerous_var in ['LD_PRELOAD', 'LD_LIBRARY_PATH', 'PYTHONPATH']:
            if dangerous_var in merged_env and dangerous_var not in (env or {}):
                del merged_env[dangerous_var]

        logger.debug(f"Running command: {' '.join(str(c) for c in cmd)}")

        try:
            result = subprocess.run(
                cmd,
                check=check,
                capture_output=capture_output,
                text=True,
                cwd=str(self.config.project_root),
                env=merged_env,
                timeout=300,  # 5 minute timeout
            )
            if result.stdout:
                logger.debug(f"stdout: {result.stdout[:500]}")
            if result.stderr:
                logger.debug(f"stderr: {result.stderr[:500]}")
            return result
        except subprocess.TimeoutExpired:
            logger.error("Command timed out after 300 seconds")
            raise
        except subprocess.CalledProcessError as e:
            logger.error(f"Command failed with return code {e.returncode}")
            if e.stdout:
                logger.error(f"stdout: {e.stdout[:1000]}")
            if e.stderr:
                logger.error(f"stderr: {e.stderr[:1000]}")
            raise

